package com.example.web.controller;

import jakarta.servlet.http.HttpServletRequest;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.util.HtmlUtils;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

@Controller
public class CommentController {

    private final CommentService commentService;

    public CommentController(CommentService commentService) {
        this.commentService = commentService;
    }

    @GetMapping("/comments")
    public String listComments(Model model) {
        List<Comment> comments = commentService.findAllComments();
        model.addAttribute("comments", comments);
        return "comments";
    }

    @GetMapping("/comments/post/{postId}")
    public String listCommentsForPost(@PathVariable Long postId, Model model) {
        List<Comment> comments = commentService.findCommentsByPostId(postId);
        model.addAttribute("comments", comments);
        model.addAttribute("postId", postId);
        return "comments";
    }

    public interface CommentService {
        List<Comment> findAllComments();
        List<Comment> findCommentsByPostId(Long postId);
    }

    public static class InMemoryCommentService implements CommentService {
        private final List<Comment> comments = new ArrayList<>();

        public InMemoryCommentService() {
            comments.add(new Comment(1L, 101L, "Alice", "<b>Hello</b>, this is a <i>great</i> post!"));
            comments.add(new Comment(2L, 101L, "Bob", "I <u>agree</u> with Alice."));
            comments.add(new Comment(3L, 102L, "Charlie", "Nice article with <strong>useful</strong> tips."));
        }

        @Override
        public List<Comment> findAllComments() {
            return Collections.unmodifiableList(comments);
        }

        @Override
        public List<Comment> findCommentsByPostId(Long postId) {
            List<Comment> result = new ArrayList<>();
            for (Comment c : comments) {
                if (c.getPostId() != null && c.getPostId().equals(postId)) {
                    result.add(c);
                }
            }
            return result;
        }
    }

    public static class Comment {
        private Long id;
        private Long postId;
        private String author;
        private String content;

        public Comment() {
        }

        public Comment(Long id, Long postId, String author, String content) {
            this.id = id;
            this.postId = postId;
            this.author = author;
            this.content = content;
        }

        public Long getId() {
            return id;
        }

        public void setId(Long id) {
            this.id = id;
        }

        public Long getPostId() {
            return postId;
        }

        public void setPostId(Long postId) {
            this.postId = postId;
        }

        public String getAuthor() {
            return author;
        }

        public void setAuthor(String author) {
            this.author = author;
        }

        public String getContent() {
            return content;
        }

        public void setContent(String content) {
            this.content = content;
        }

        public String getEscapedContent() {
            return HtmlUtils.htmlEscape(content);
        }
    }
}